  const { documentId } = req.body;

  if (!documentId) {
    return res.status(400).json({ error: 'documentId is required' });
  }

  const shareLink = generateShareableLink(documentId);

  res.json({
    success: true,
    shareLink: shareLink
  });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);

  // Example usage
  console.log('\nExample usage:');
  const exampleLink = generateShareableLink('doc-12345');
  console.log(`Generated share link: ${exampleLink}`);

  // Verify the token
  const token = exampleLink.split('/share/')[1];
  const verified = verifyToken(token);
  console.log(`Verified document ID: ${verified}`);
});

export { generateShareableLink, verifyToken };
