```typescript
import Anthropic from "@anthropic-ai/sdk";
import crypto from "crypto";

const client = new Anthropic();

interface TokenGenerationRequest {
  endpoint_url: string;
  owner_id: string;
}

interface TokenGenerationResponse {
  token: string;
  payload: string;
  signature: string;
}

async function generateWebhookVerificationToken(
  request: TokenGenerationRequest
): Promise<TokenGenerationResponse> {
  const { endpoint_url, owner_id } = request;

  // Create the payload containing the verification data
  const payload = JSON.stringify({
    endpoint_url,
    owner_id,
    timestamp: Date.now(),
    nonce: crypto.randomBytes(16).toString("hex"),
  });

  // Get the HMAC secret from environment or generate one
  const hmacSecret =
    process.env.WEBHOOK_HMAC_SECRET || crypto.randomBytes(32).toString("hex");

  // Generate HMAC signature
  const signature = crypto
    .createHmac("sha256", hmacSecret)
    .update(payload)
    .digest("hex");

  // Create the token in payload.signature format
  const token = `${Buffer.from(payload).toString("base64")}.${signature}`;

  // Use Claude to validate the token structure
  const message = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    messages: [
      {
        role: "user",
        content: `Validate that this webhook verification token follows security best practices:

Token: ${token}
Payload: ${payload}
Signature: ${signature}

Check that:
1. The token contains both payload and signature separated by a dot
2. The payload is base64 encoded
3. The signature is a valid hex string
4. The payload contains required fields: endpoint_url, owner_id, timestamp, nonce

Respond with "VALID" if all checks pass, or explain any issues.`,
      },
    ],
  });

  const validationResponse =
    message.content[0].type === "text" ? message.content[0].text : "";

  if (!validationResponse.includes("VALID")) {
    throw new Error(`Token validation failed: ${validationResponse}`);
  }

  return {
    token,
    payload: Buffer.from(payload).toString("base64"),
    signature,
  };
}

function verifyWebhookToken(
  token: string,
  hmacSecret: string
): { valid: boolean; data?: Record<string, unknown> } {
  try {
    const [encodedPayload, signature] = token.split(".");

    if (!encodedPayload || !signature) {
      return { valid: false };
    }

    // Decode the payload
    const payload = Buffer.from(encodedPayload, "base64").toString("utf-8");

    // Verify the signature using timing-safe comparison
    const expectedSignature = crypto
      .createHmac("sha256", hmacSecret)
      .update(payload)
      .digest("hex");

    const signatureBuffer = Buffer.from(signature);
    const expectedSignatureBuffer = Buffer.from(expectedSignature);

    // Use timing-safe comparison to prevent timing attacks
    const isValid = crypto.timingSafeEqual(
      signatureBuffer,
      expectedSignatureBuffer
    );

    if (isValid) {
      const data = JSON.parse(payload);
      return { valid: true, data };
    }

    return { valid: false };
  } catch (error) {
    return { valid: false };
  }
}

// Main execution
async function main() {
  try {
    // Generate a verification token
    const tokenResponse = await generateWebhookVerificationToken({
      endpoint_url: "https://example.com/webhook/verify",
      owner_id: "user_12345",
    });

    console.log("Generated Webhook Verification Token:");
    console.log("Token:", tokenResponse.token);
    console.log("Payload (base64):", tokenResponse.payload);
    console.log("Signature:", tokenResponse.signature);

    // Verify the token
    const hmacSecret =
      process.env.WEBHOOK_HMAC_SECRET || crypto.randomBytes(32).toString("hex");
    const verification = verifyWebhookToken(tokenResponse.token, hmacSecret);

    console.log("\nToken Verification Result:");
    console.log("Valid:", verification.valid);
    if (verification.data) {
      console.log("Data:", verification.data);
    }
  } catch (error) {
    console.error("Error:", error);
    process.exit(1);
  }
}

main();
