import Anthropic from "@anthropic-ai/sdk";
import crypto from "crypto";

const client = new Anthropic();

async function generateWebhookVerificationToken(
  endpoint_url: string,
  owner_id: string
): Promise<string> {
  const message = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    messages: [
      {
        role: "user",
        content: `Generate a secure random token for webhook verification. The token should be suitable for proving ownership of a webhook endpoint. Return only the token string, nothing else.`,
      },
    ],
  });

  const tokenContent = message.content[0];
  if (tokenContent.type !== "text") {
    throw new Error("Unexpected response type from Claude");
  }

  const baseToken = tokenContent.text.trim();

  // Create HMAC signature for the token
  const secret = process.env.WEBHOOK_SECRET || "default-webhook-secret";
  const payload = JSON.stringify({
    token: baseToken,
    endpoint_url: endpoint_url,
    owner_id: owner_id,
    timestamp: Date.now(),
  });

  const signature = crypto
    .createHmac("sha256", secret)
    .update(payload)
    .digest("hex");

  // Return token in payload.signature format
  const verificationToken = `${Buffer.from(payload).toString("base64")}.${signature}`;

  return verificationToken;
}

async function verifyWebhookToken(
  token: string,
  endpoint_url: string,
  owner_id: string
): Promise<boolean> {
  const secret = process.env.WEBHOOK_SECRET || "default-webhook-secret";

  const [payloadB64, signature] = token.split(".");

  if (!payloadB64 || !signature) {
    return false;
  }

  try {
    const payload = Buffer.from(payloadB64, "base64").toString("utf-8");
    const parsedPayload = JSON.parse(payload);

    // Verify the signature using timing-safe comparison
    const expectedSignature = crypto
      .createHmac("sha256", secret)
      .update(payload)
      .digest("hex");

    const signatureBuffer = Buffer.from(signature);
    const expectedBuffer = Buffer.from(expectedSignature);

    if (!crypto.timingSafeEqual(signatureBuffer, expectedBuffer)) {
      return false;
    }

    // Verify the payload contents
    if (
      parsedPayload.endpoint_url !== endpoint_url ||
      parsedPayload.owner_id !== owner_id
    ) {
      return false;
    }

    // Check if token is not too old (24 hours)
    const tokenAge = Date.now() - parsedPayload.timestamp;
    const maxAge = 24 * 60 * 60 * 1000; // 24 hours in milliseconds

    if (tokenAge > maxAge) {
      return false;
    }

    return true;
  } catch {
    return false;
  }
}

// Main execution
async function main() {
  const endpoint_url = "https://example.com/webhook";
  const owner_id = "user_12345";

