        request_id = f"report_{request_counter}"
        report_requests[request_id] = {
            "id": request_id,
            "type": report_type,
            "parameters": parameters,
            "status": "queued",
            "created_at": datetime.now().isoformat(),
            "completed_at": None,
            "result": None,
        }
        conversation_history[request_id] = []
    return request_id


