        # Try to extract JSON from the response
        json_start = response_text.find('{')
        json_end = response_text.rfind('}') + 1
        if json_start != -1 and json_end > json_start:
            json_str = response_text[json_start:json_end]
            result = json.loads(json_str)
        else:
            result = {"valid": False, "reason": "Invalid response format", "delivery_status": "failed"}
    except json.JSONDecodeError:
        result = {"valid": False, "reason": "Failed to parse response", "delivery_status": "failed"}

    return result

def mark_notification_as_sent(notification_id):
    """Mark a notification as sent in the database."""
    for notification in notifications_db:
        if notification["id"] == notification_id:
            notification["status"] = "sent"
            notification["sent_at"] = datetime.now().isoformat()
            return True
    return False

def send_queued_notifications():
    """Main cron job function to process pending notifications."""
    print(f"[{datetime.now().isoformat()}] Starting notification processing...")

    # Get all pending notifications
    pending_notifications = get_pending_notifications()

    if not pending_notifications:
        print(f"[{datetime.now().isoformat()}] No pending notifications to process.")
        return {"processed": 0, "successful": 0, "failed": 0}

    print(f"[{datetime.now().isoformat()}] Found {len(pending_notifications)} pending notifications.")

    stats = {
        "processed": 0,
        "successful": 0,
        "failed": 0,
        "details": []
    }

    for notification in pending_notifications:
        try:
            print(f"[{datetime.now().isoformat()}] Processing notification ID: {notification['id']}")

            # Send the notification via API
            api_result = send_notification_via_api(notification)

            # Check if the notification was sent successfully
            if api_result.get("delivery_status") == "success" and api_result.get("valid"):
                # Mark as sent in the database
                if mark_notification_as_sent(notification["id"]):
                    stats["successful"] += 1
                    print(f"[{datetime.now().isoformat()}] ✓ Notification {notification['id']} sent successfully")
                    stats["details"].append({
                        "notification_id": notification["id"],
                        "status": "sent",
                        "message": notification["message"]
                    })
                else:
                    stats["failed"] += 1
                    print(f"[{datetime.now().isoformat()}] ✗ Failed to update notification {notification['id']} status")
                    stats["details"].append({
                        "notification_id": notification["id"],
                        "status": "failed",
                        "reason": "Failed to update database"
                    })
            else:
                stats["failed"] += 1
                reason = api_result.get("reason", "Unknown error")
                print(f"[{datetime.now().isoformat()}] ✗ Notification {notification['id']} failed: {reason}")
                stats["details"].append({
                    "notification_id": notification["id"],
                    "status": "failed",
                    "reason": reason
                })

            stats["processed"] += 1

        except Exception as e:
            stats["failed"] += 1
            stats["processed"] += 1
            print(f"[{datetime.now().isoformat()}] ✗ Error processing notification {notification['id']}: {str(e)}")
            stats["details"].append({
                "notification_id": notification["id"],
                "status": "error",
                "error": str(e)
            })

    # Print summary
    print(f"[{datetime.now().isoformat()}] Notification processing complete.")
    print(f"[{datetime.now().isoformat()}] Summary - Processed: {stats['processed']}, Successful: {stats['successful']}, Failed: {stats['failed']}")

    return stats

