                # Try to find it in common locations
                for name in epub.namelist():
                    if name.endswith('content.opf'):
                        opf_path = name
                        break

        # Read and parse the OPF file
        try:
            opf_content = epub.read(opf_path)
            opf_root = ET.fromstring(opf_content)
        except KeyError:
            return chapters

        # Define namespaces
        ns = {
            'opf': 'http://www.idpf.org/2007/opf',
            'ncx': 'http://www.daisy.org/z3986/2005/ncx/'
        }

        # Get the base directory of the OPF file
        opf_dir = str(Path(opf_path).parent)
        if opf_dir == '.':
            opf_dir = ''

        # Extract manifest items (chapter files)
        manifest = opf_root.find('.//opf:manifest', ns)
        if manifest is None:
            manifest = opf_root.find('.//manifest')

        # Extract spine (reading order)
        spine = opf_root.find('.//opf:spine', ns)
        if spine is None:
            spine = opf_root.find('.//spine')

        if manifest is None or spine is None:
            return chapters

        # Create a mapping of item IDs to their paths
        item_map = {}
        for item in manifest.findall('.//opf:item', ns) or manifest.findall('.//item'):
            item_id = item.get('id')
            href = item.get('href')
            if item_id and href:
                # Resolve relative paths
                if opf_dir:
                    full_path = str(Path(opf_dir) / href)
                else:
                    full_path = href
                item_map[item_id] = full_path

        # Process chapters in spine order
        chapter_num = 1
        for itemref in spine.findall('.//opf:itemref', ns) or spine.findall('.//itemref'):
            idref = itemref.get('idref')
            if idref and idref in item_map:
                chapter_path = item_map[idref]

                try:
                    # Read the chapter HTML
                    html_content = epub.read(chapter_path).decode('utf-8', errors='ignore')

                    # Extract title from HTML if possible
                    title = f"Chapter {chapter_num}"
                    try:
                        html_root = ET.fromstring(f"<root>{html_content}</root>")
                        # Try to find title in various common locations
                        title_elem = html_root.find('.//title')
                        if title_elem is None:
                            title_elem = html_root.find('.//h1')
                        if title_elem is None:
                            title_elem = html_root.find('.//h2')
                        if title_elem is not None and title_elem.text:
                            title = title_elem.text.strip()
                    except ET.ParseError:
                        # If XML parsing fails, try simple regex
                        import re
                        title_match = re.search(r'<title[^>]*>([^<]+)</title>', html_content, re.IGNORECASE)
                        if title_match:
                            title = title_match.group(1).strip()
                        else:
                            h1_match = re.search(r'<h[1-2][^>]*>([^<]+)</h[1-2]>', html_content, re.IGNORECASE)
                            if h1_match:
                                title = h1_match.group(1).strip()

                    chapters.append({
                        "chapter": chapter_num,
                        "title": title,
                        "html": html_content
                    })
                    chapter_num += 1
                except KeyError:
                    # File not found in archive, skip
                    continue

    return chapters


if __name__ == "__main__":
    # Example usage
    import sys

    if len(sys.argv) > 1:
        epub_file = sys.argv[1]
        chapters = parse_epub(epub_file)

        for chapter in chapters:
            print(f"Chapter {chapter['chapter']}: {chapter['title']}")
            print(f"HTML length: {len(chapter['html'])} characters")
            print("---")
    else:
        print("Usage: python solution.py <path_to_epub_file>")
