import zipfile
import xml.etree.ElementTree as ET
from pathlib import Path


def parse_epub(file_path: str) -> list[dict]:
    """
    Parse an EPUB file and extract chapter information.

    Args:
        file_path: Path to the EPUB file

    Returns:
        List of dictionaries containing chapter number, title, and HTML content
    """
    chapters = []

    with zipfile.ZipFile(file_path, 'r') as epub_zip:
        # Find the content.opf file (usually in META-INF/container.xml)
        try:
            container_xml = epub_zip.read('META-INF/container.xml')
            container_root = ET.fromstring(container_xml)

            # Extract the path to content.opf from container.xml
            ns = {'container': 'urn:oasis:names:tc:opendocument:xmlns:container'}
            rootfile = container_root.find('.//container:rootfile', ns)
            opf_path = rootfile.get('full-path') if rootfile is not None else 'content.opf'
        except (KeyError, ET.ParseError):
            # Fallback to common location
            opf_path = 'content.opf'

        # Read the content.opf file
        try:
            opf_content = epub_zip.read(opf_path)
            opf_root = ET.fromstring(opf_content)
        except KeyError:
            # Try alternative paths
            for file_info in epub_zip.filelist:
                if file_info.filename.endswith('content.opf'):
                    opf_path = file_info.filename
                    opf_content = epub_zip.read(opf_path)
                    opf_root = ET.fromstring(opf_content)
                    break
            else:
                return chapters

        # Define namespaces
        ns = {
            'opf': 'http://www.idpf.org/2007/opf',
            'ncx': 'http://www.daisy.org/z3986/2005/ncx/'
        }

        # Get the base directory of the OPF file
        opf_dir = str(Path(opf_path).parent)
        if opf_dir == '.':
            opf_dir = ''

        # Extract manifest items (all files referenced in the book)
        manifest = {}
        for item in opf_root.findall('.//opf:manifest/opf:item', ns):
            item_id = item.get('id')
            href = item.get('href')
            media_type = item.get('media-type', '')

            if item_id and href:
                # Resolve relative paths
                if opf_dir:
                    full_path = str(Path(opf_dir) / href)
                else:
                    full_path = href
                manifest[item_id] = {
                    'href': full_path,
                    'media_type': media_type
                }

        # Extract spine (reading order)
        spine_items = []
        spine = opf_root.find('.//opf:spine', ns)
        if spine is not None:
            for itemref in spine.findall('opf:itemref', ns):
                idref = itemref.get('idref')
                if idref and idref in manifest:
                    spine_items.append(manifest[idref])

        # Process each chapter in spine order
        chapter_num = 1
        for item in spine_items:
            href = item['href']
            media_type = item['media_type']

            # Only process HTML/XHTML files
            if 'html' in media_type or 'xml' in media_type or href.endswith(('.html', '.xhtml', '.htm')):
                try:
                    html_content = epub_zip.read(href).decode('utf-8', errors='ignore')

                    # Extract title from HTML if possible
                    title = f"Chapter {chapter_num}"
                    try:
                        html_root = ET.fromstring(html_content)
                        title_elem = html_root.find('.//title')
                        if title_elem is not None and title_elem.text:
                            title = title_elem.text.strip()
                        else:
                            # Try to find h1 or h2
                            for tag in ['h1', 'h2', 'h3']:
                                heading = html_root.find(f'.//{tag}')
                                if heading is not None and heading.text:
                                    title = heading.text.strip()
                                    break
                    except ET.ParseError:
                        # If XML parsing fails, try to extract title from HTML string
                        import re
                        title_match = re.search(r'<title[^>]*>([^<]+)</title>', html_content, re.IGNORECASE)
                        if title_match:
                            title = title_match.group(1).strip()

                    chapters.append({
                        'chapter': chapter_num,
                        'title': title,
                        'html': html_content
                    })
                    chapter_num += 1
                except KeyError:
                    # File not found in zip, skip
                    continue

    return chapters


if __name__ == "__main__":
    # Example usage
    import sys

    if len(sys.argv) > 1:
        epub_file = sys.argv[1]
        chapters = parse_epub(epub_file)

        print(f"Found {len(chapters)} chapters:")
        for chapter in chapters:
            print(f"  Chapter {chapter['chapter']}: {chapter['title']}")
            print(f"    HTML length: {len(chapter['html'])} characters")
    else:
        print("Usage: python solution.py <epub_file_path>")
