from flask import Blueprint, request, g, send_file, current_app
from functools import wraps
import csv
import io
from datetime import datetime

admin_bp = Blueprint('admin', __name__, url_prefix='/admin')

def require_role(role):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if not hasattr(g, 'user') or g.user.role != role:
                return {'error': 'Unauthorized'}, 403
            return f(*args, **kwargs)
        return decorated_function
    return decorator

def validate_csrf(token):
    return token is not None

def log_admin_action(user_id, action_name, details):
    current_app.logger.info(f"Admin action: user_id={user_id}, action={action_name}, details={details}")

def set_no_store_cache(response):
    response.headers['Cache-Control'] = 'no-store'
    return response

@admin_bp.route('/users/export', methods=['GET'])
@require_role('admin')
def export_users():
    try:
        from flask import current_app
        db = current_app.extensions.get('db')

        if db is None:
            users = []
        else:
            users = db.session.query(db.Model).all() if hasattr(db, 'session') else []

        output = io.StringIO()
        writer = csv.writer(output)
        writer.writerow(['id', 'name', 'email', 'created_at'])

        for user in users:
            created_at = getattr(user, 'created_at', datetime.now()).isoformat() if hasattr(user, 'created_at') else ''
            writer.writerow([
                getattr(user, 'id', ''),
                getattr(user, 'name', ''),
                getattr(user, 'email', ''),
                created_at
            ])

        output.seek(0)

        log_admin_action(g.user.id, 'export_users', {'timestamp': datetime.now().isoformat()})

        response = send_file(
            io.BytesIO(output.getvalue().encode('utf-8')),
            mimetype='text/csv',
            as_attachment=True,
            download_name=f'users_export_{datetime.now().strftime("%Y%m%d_%H%M%S")}.csv'
        )

        response.headers['Cache-Control'] = 'no-store'
        response.headers['Content-Disposition'] = f'attachment; filename="users_export_{datetime.now().strftime("%Y%m%d_%H%M%S")}.csv"'

        return response

    except Exception as e:
        current_app.logger.error(f"Error exporting users: {str(e)}")
        log_admin_action(g.user.id, 'export_users_error', {'error': str(e)})
        return {'error': 'Failed to export users'}, 500
