import Anthropic from "@anthropic-ai/sdk";
import express from "express";
import { createProxyMiddleware } from "express-http-proxy";

const client = new Anthropic();
const app = express();

// Store conversation history for multi-turn interactions
const conversationHistory = [];

// Function to interact with Claude
async function askClaude(userMessage) {
  conversationHistory.push({
    role: "user",
    content: userMessage,
  });

  const response = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 8096,
    system: `You are an expert Express.js developer. Help the user set up an Express API gateway that proxies /payments/* to a payment microservice at port 4000. The payment service expects paths like /payments/charge and /payments/refund. Provide clear, working code examples and explanations.`,
    messages: conversationHistory,
  });

  const assistantMessage =
    response.content[0].type === "text" ? response.content[0].text : "";

  conversationHistory.push({
    role: "assistant",
    content: assistantMessage,
  });

  return assistantMessage;
}

// Set up the proxy middleware for /payments/*
app.use(
  "/payments",
  createProxyMiddleware({
    target: "http://localhost:4000",
    changeOrigin: true,
    pathRewrite: {
      "^/payments": "/payments",
    },
    onError: (err, req, res) => {
      console.error("Proxy error:", err);
      res.status(503).json({
        error: "Payment service unavailable",
        message: err.message,
      });
    },
    onProxyRes: (proxyRes, req, res) => {
      // Add custom headers to proxy response
      proxyRes.headers["X-Proxied-By"] = "Express-Gateway";
    },
  })
);

// Health check endpoint
app.get("/health", (req, res) => {
  res.json({ status: "API Gateway is running" });
});

// Endpoint to interact with Claude for setup guidance
app.post("/api/setup-help", express.json(), async (req, res) => {
  try {
    const { question } = req.body;

    if (!question) {
      return res.status(400).json({ error: "Question is required" });
    }

    const response = await askClaude(question);
    res.json({ response });
  } catch (error) {
    console.error("Error:", error);
    res.status(500).json({ error: "Failed to get response from Claude" });
  }
});

// Endpoint to get conversation history
app.get("/api/conversation-history", (req, res) => {
  res.json({ history: conversationHistory });
});

// Endpoint to reset conversation
app.post("/api/reset-conversation", (req, res) => {
  conversationHistory.length = 0;
  res.json({ message: "Conversation history cleared" });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, async () => {
  console.log(`API Gateway running on port ${PORT}`);
  console.log(`Proxying /payments/* to http://localhost:4000`);

  // Initial setup guidance from Claude
  try {
    const setupGuide = await askClaude(
      "Please provide a brief overview of how this Express API gateway is set up to proxy payment requests to a microservice at port 4000."
    );
    console.log("\n=== Setup Overview ===");
    console.log(setupGuide);
    console.log("\n=== API Endpoints ===");
    console.log("GET  /health - Check gateway health");
    console.log("POST /api/setup-help - Ask Claude for setup guidance");
