app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'dev-secret-key-change-in-production')

class BookmarkForm(FlaskForm):
    title = StringField('Title', validators=[DataRequired()])
    url = StringField('URL', validators=[DataRequired(), URL()])
    tags = StringField('Tags', validators=[Optional()])
    submit = SubmitField('Save Bookmark')

@app.route('/')
def index():
    return redirect(url_for('add_bookmark'))

@app.route('/bookmark/add', methods=['GET', 'POST'])
def add_bookmark():
    form = BookmarkForm()
    if form.validate_on_submit():
        flash(f'Bookmark "{form.title.data}" added successfully!', 'success')
        return redirect(url_for('add_bookmark'))
    return render_template('bookmark_form.html', form=form)

if __name__ == '__main__':
    app.run(debug=True)
