@celery.task(bind=True)
def long_running_task(self, duration):
    """Simulate a long-running task"""
    try:
        self.update_state(state='PROGRESS', meta={'current': 0, 'total': duration})

        for i in range(duration):
            # Simulate work
            import time
            time.sleep(1)
            self.update_state(state='PROGRESS', meta={'current': i + 1, 'total': duration})

        return {'status': 'Task completed!', 'result': f'Processed for {duration} seconds'}
    except Exception as exc:
        self.update_state(state='FAILURE', meta={'exc_type': type(exc).__name__, 'exc_message': str(exc)})
        raise


