from flask import request, g, abort
from functools import wraps
from datetime import datetime

def role_required(required_role):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if g.user['role'] != required_role:
                abort(403)
            return f(*args, **kwargs)
        return decorated_function
    return decorator

@app.route('/documents/<int:doc_id>/edit', methods=['POST'])
@role_required('editor')
def edit_document(doc_id):
    # Get document from database
    document = db.session.query(Document).filter_by(id=doc_id).first()

    # 404 check
    if not document:
        abort(404)

    # Ownership check
    if document.author_id != g.user['id']:
        abort(403)

    # Get form data
    title = request.form.get('title')
    content = request.form.get('content')

    # Update document
    document.title = title
    document.content = content
    document.updated_at = datetime.utcnow()

    db.session.commit()

    return {'message': 'Document updated successfully', 'document_id': doc_id}, 200
