    with app.app_context():
        db = get_db()
        cursor = db.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                email TEXT NOT NULL UNIQUE,
                bio TEXT
            )
        ''')
        db.commit()

class ProfileEditSchema(BaseModel):
    name: str
    email: EmailStr
    bio: str | None = None

