from flask import Flask, request, jsonify
import anthropic
import json

app = Flask(__name__)

# In-memory storage for items
items_db = {}
next_id = 1

def update_item(conn, item_id, name, price):
    """Model function to update an item in the database."""
    if item_id not in items_db:
        return {"error": f"Item with id {item_id} not found"}, 404

    items_db[item_id] = {
        "id": item_id,
        "name": name,
        "price": price
    }
    return items_db[item_id], 200

def validate_name(name):
    """Validate item name."""
    if not isinstance(name, str):
        return False, "Name must be a string"
    if len(name) < 1 or len(name) > 200:
        return False, "Name must be between 1 and 200 characters"
    return True, None

def validate_price(price):
    """Validate item price."""
    try:
        price_float = float(price)
        if price_float <= 0:
            return False, "Price must be a positive number"
        return True, None
    except (ValueError, TypeError):
        return False, "Price must be a valid positive number"

@app.route('/items', methods=['POST'])
def create_item():
    """Create a new item with name and price."""
    data = request.get_json()

    if not data:
        return jsonify({"error": "Request body must be JSON"}), 400

    # Validate name
    name = data.get('name')
    if name is None:
        return jsonify({"error": "Name is required"}), 400

    is_valid, error_msg = validate_name(name)
    if not is_valid:
        return jsonify({"error": error_msg}), 400

    # Validate price
    price = data.get('price')
    if price is None:
        return jsonify({"error": "Price is required"}), 400

    is_valid, error_msg = validate_price(price)
    if not is_valid:
        return jsonify({"error": error_msg}), 400

    # Create the item
    global next_id
    item_id = next_id
    next_id += 1

    # Use the shared update_item function
    result, status = update_item(None, item_id, name, float(price))

    if status == 404:
        # Item doesn't exist yet, so create it
        items_db[item_id] = {
            "id": item_id,
            "name": name,
            "price": float(price)
        }
        return jsonify(items_db[item_id]), 201

    return jsonify(result), status

@app.route('/items/<int:item_id>/edit', methods=['POST'])
def edit_item(item_id):
    """Update an existing item's name and price."""
    data = request.get_json()

    if not data:
        return jsonify({"error": "Request body must be JSON"}), 400

    # Check if item exists
    if item_id not in items_db:
        return jsonify({"error": f"Item with id {item_id} not found"}), 404

    # Get current values if not provided
    current_item = items_db[item_id]
    name = data.get('name', current_item['name'])
    price = data.get('price', current_item['price'])

    # Validate name if provided
    if 'name' in data:
        is_valid, error_msg = validate_name(name)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

    # Validate price if provided
    if 'price' in data:
        is_valid, error_msg = validate_price(price)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

    # Use the shared update_item function
    result, status = update_item(None, item_id, name, float(price))

    return jsonify(result), status

@app.route('/items', methods=['GET'])
def list_items():
    """List all items."""
    return jsonify(list(items_db.values())), 200

if __name__ == '__main__':
    app.run(debug=True)
